import { GoogleGenAI, Type } from "@google/genai";
import { ResumeAnalysis, InterviewFeedback, Roadmap } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// --- Resume Analysis (Extract + Analyze) ---

export const analyzeResume = async (
  input: { text?: string; fileData?: string; mimeType?: string },
  targetRole: string,
  experienceLevel: string
): Promise<ResumeAnalysis> => {
  const model = "gemini-2.5-flash";

  if (!input.text && !input.fileData) {
      throw new Error("Please upload a resume file or provide text.");
  }

  const promptText = `
    You are the Resume Intelligence Model for Campus Media.

    STRICT RULES:
    1. Analyze ONLY the resume provided (text or PDF).
    2. STRICTLY EXTRACT information that explicitly exists.
    3. DO NOT hallucinate, guess, or create data.
    4. If a section (like Projects or Experience) is missing, return empty arrays.
    5. If the resume is unreadable, return a low score and explain in the summary.
    6. DO NOT include "Raw Content".

    TASKS:
    1. EXTRACT key sections actually found in the resume:
       - Personal Info (Name, Email, Links)
       - Candidate's own Summary/Objective (if present)
       - Skills (Key, Technical, Soft)
       - Projects (Name, Stack, Description)
       - Experience (Role, Company, Duration, Responsibilities)
       - Education
       - Achievements & Certifications

    2. GENERATE INSIGHTS ONLY based on resume content:
       - Strengths (based strictly on extracted text)
       - Weaknesses / Missing elements (based on what is NOT present)
       - Professional improvements
       - ATS Score (0–100)
       - Skill Gap Analysis for the role: "${targetRole}"

    3. MAKE SUGGESTIONS ONLY from real resume data:
       - Identify missing sections
       - Identify weakly written areas
       - Suggest restructuring for ATS
       - Suggest grammar and formatting improvements
       - Suggest additional skills relevant to the candidate’s domain

    TARGET ROLE: "${targetRole}"
    EXPERIENCE LEVEL: "${experienceLevel}"
  `;

  const parts: any[] = [{ text: promptText }];

  if (input.fileData && input.mimeType) {
    parts.push({
      inlineData: {
        data: input.fileData,
        mimeType: input.mimeType
      }
    });
  } else if (input.text) {
    parts.push({ text: `RESUME TEXT: "${input.text.slice(0, 30000)}"` });
  }

  const response = await ai.models.generateContent({
    model,
    contents: { parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          extractedData: {
            type: Type.OBJECT,
            properties: {
              personalInfo: {
                 type: Type.OBJECT,
                 properties: {
                    name: { type: Type.STRING },
                    email: { type: Type.STRING },
                    phone: { type: Type.STRING },
                    links: { type: Type.ARRAY, items: { type: Type.STRING } }
                 }
              },
              summary: { type: Type.STRING, description: "The candidate's own summary found in the resume" },
              keySkills: { type: Type.ARRAY, items: { type: Type.STRING } },
              technicalSkills: { type: Type.ARRAY, items: { type: Type.STRING } },
              softSkills: { type: Type.ARRAY, items: { type: Type.STRING } },
              projects: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    techStack: { type: Type.ARRAY, items: { type: Type.STRING } },
                    description: { type: Type.STRING }
                  }
                }
              },
              workExperience: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    role: { type: Type.STRING },
                    company: { type: Type.STRING },
                    duration: { type: Type.STRING },
                    description: { type: Type.STRING }
                  }
                }
              },
              education: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    degree: { type: Type.STRING },
                    institution: { type: Type.STRING },
                    year: { type: Type.STRING }
                  }
                }
              },
              achievements: { type: Type.ARRAY, items: { type: Type.STRING } },
              certifications: { type: Type.ARRAY, items: { type: Type.STRING } }
            }
          },
          score: { type: Type.NUMBER },
          atsCompatibility: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
          missingSkills: { type: Type.ARRAY, items: { type: Type.STRING } },
          optimizedPoints: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                original: { type: Type.STRING },
                optimized: { type: Type.STRING },
                reason: { type: Type.STRING }
              }
            }
          },
          summary: { type: Type.STRING, description: "AI Verdict/Summary of the resume quality" }
        }
      },
    },
  });

  if (!response.text) throw new Error("No response from AI");
  return JSON.parse(response.text) as ResumeAnalysis;
};

// --- Feedback Generation ---

export const generateFeedbackFromTranscript = async (
  transcript: string
): Promise<InterviewFeedback> => {
  const model = "gemini-2.5-flash";

  const prompt = `
    You are a Senior Technical Interviewer. Analyze the following voice interview transcript.
    TRANSCRIPT:
    "${transcript}"

    Provide a strict performance report.
    - Identify exactly where the candidate failed to answer correctly.
    - Provide "Corrected Answers" for mistakes.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          mistakes: { type: Type.ARRAY, items: { type: Type.STRING } },
          improvements: { type: Type.ARRAY, items: { type: Type.STRING } },
          communicationTips: { type: Type.ARRAY, items: { type: Type.STRING } },
          technicalTips: { type: Type.ARRAY, items: { type: Type.STRING } },
          correctedAnswers: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                originalAnswer: { type: Type.STRING },
                idealAnswer: { type: Type.STRING },
              },
            },
          },
          roadmap: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
      },
    },
  });

  if (!response.text) throw new Error("No feedback generated");
  return JSON.parse(response.text) as InterviewFeedback;
};

