export const generateRoadmap = async (
  currentSkills: string[],
  targetDomain: string
): Promise<Roadmap> => {
  const model = "gemini-2.5-flash";

  const prompt = `
    Create a personalized 6-Stage Learning Roadmap for a student targeting the domain: "${targetDomain}".

    Current Skills: ${currentSkills.join(", ")}.

    Requirements:
    - Stage 1: Fundamentals
    - Stage 2: Intermediate
    - Stage 3: Advanced
    - Stage 4: Projects to Build
    - Stage 5: Interview Prep
    - Stage 6: Resources

    Skip what they already know well, focus on gaps.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          targetDomain: { type: Type.STRING },
          stages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stageName: { type: Type.STRING },
                description: { type: Type.STRING },
                items: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      topic: { type: Type.STRING },
                      reason: { type: Type.STRING },
                      timeEstimate: { type: Type.STRING },
                      difficulty: { type: Type.STRING, enum: ["Easy", "Medium", "Hard"] },
                      resources: { type: Type.ARRAY, items: { type: Type.STRING } }
                    }
                  }
                }
              }
            }
          }
        }
      },
    },
  });

  if (!response.text) throw new Error("Roadmap generation failed");
  return JSON.parse(response.text) as Roadmap;
};

import React, { useState } from 'react';
import { Upload, FileText, CheckCircle, AlertTriangle, Lightbulb, TrendingUp, Sparkles, ArrowRight, User, BookOpen, Briefcase, GraduationCap, Award, RefreshCw } from 'lucide-react';
import { analyzeResume } from '../services/geminiService';
import { ResumeAnalysis } from '../types';
import { useApp } from '../context/AppContext';

export const ResumeAnalyzer: React.FC = () => {
  const { updateResumeContext } = useApp();
  const [role, setRole] = useState('');
  const [level, setLevel] = useState('Entry-Level');

  // State for Input (File or Text)
  const [file, setFile] = useState<File | null>(null);
  const [resumeText, setResumeText] = useState('');
  const [inputMode, setInputMode] = useState<'file' | 'text'>('file');

  const [analysis, setAnalysis] = useState<ResumeAnalysis | null>(null);
  const [loading, setLoading] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const selectedFile = e.target.files?.[0];
    if (selectedFile) {
      setFile(selectedFile);
      setResumeText(''); // Clear text if file selected
    }
  };

  const fileToBase64 = (file: File): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = () => {
        const result = reader.result as string;
        // Remove "data:application/pdf;base64," prefix
        const base64 = result.split(',')[1];
        resolve(base64);
      };
      reader.onerror = error => reject(error);
    });
  };

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    if (inputMode === 'text' && !resumeText.trim()) {
        alert("Please paste your resume text to proceed.");
        return;
    }
    if (inputMode === 'file' && !file) {
        alert("Please select a resume file.");
        return;
    }
    if (!role) {
        alert("Please enter a target job role.");
        return;
    }

    setLoading(true);
    setAnalysis(null);
    try {
      let inputData: { text?: string; fileData?: string; mimeType?: string } = {};

      if (inputMode === 'file' && file) {
          const base64 = await fileToBase64(file);
          inputData = { 
            fileData: base64, 
            mimeType: file.type 
          };
      } else {
          inputData = { text: resumeText };
      }

      const result = await analyzeResume(inputData, role, level);
      setAnalysis(result);

      // Save globally for Interview and Roadmap (save text if available, or just extracted data)
      updateResumeContext(resumeText || "Extracted from PDF", result.extractedData);
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Failed to analyze resume. Please ensure the file is a valid PDF or Text.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="h-[calc(100vh-6rem)] grid grid-cols-1 lg:grid-cols-12 gap-6">
      {/* Input Column */}
      <div className="lg:col-span-4 flex flex-col gap-6 overflow-y-auto pr-2">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h2 className="text-xl font-bold text-slate-800 mb-2 flex items-center gap-2">
            <Upload className="text-indigo-600" /> Resume Setup
          </h2>
          <p className="text-xs text-slate-500 mb-6">
            Upload a PDF or paste text. The AI will strict extract and analyze data without hallucination.
          </p>

          <form onSubmit={handleAnalyze} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-slate-700 mb-1">Target Job Role</label>
              <input 
                type="text"
