export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  // --- State Initialization ---

  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('currentUser');
    return saved ? JSON.parse(saved) : null;
  });

  const [users, setUsers] = useState<User[]>(() => {
    const saved = localStorage.getItem('users');
    return saved ? JSON.parse(saved) : MOCK_USERS;
  });

  const [jobs, setJobs] = useState<Job[]>(() => {
    const saved = localStorage.getItem('jobs');
    return saved ? JSON.parse(saved) : MOCK_JOBS;
  });

  const [questions, setQuestions] = useState<Question[]>(() => {
    const saved = localStorage.getItem('questions');
    return saved ? JSON.parse(saved) : MOCK_QUESTIONS;
  });

  const [notes, setNotes] = useState<Note[]>(() => []);

  const [messages, setMessages] = useState<ChatMessage[]>(() => {
    const saved = localStorage.getItem('messages');
    return saved ? JSON.parse(saved) : MOCK_MESSAGES;
  });

  const [resumeContext, setResumeContext] = useState<ResumeContextState>({ rawText: '', extractedData: null });

  const [resumeSubmissions, setResumeSubmissions] = useState<ResumeSubmission[]>(() => {
    const saved = localStorage.getItem('resumeSubmissions');
    return saved ? JSON.parse(saved) : MOCK_RESUME_SUBMISSIONS;
  });

  const [systemConfig, setSystemConfig] = useState<SystemConfig>(() => {
    const saved = localStorage.getItem('systemConfig');
    return saved ? JSON.parse(saved) : {
      announcement: "Welcome to Campus Media! Resume Analyzer V2 is now live.",
      allowSignups: true,
      maintenanceMode: false,
      interviewCategories: ['Technical', 'HR', 'Behavioral']
    };
  });

  // --- Persistence ---
  useEffect(() => localStorage.setItem('currentUser', JSON.stringify(currentUser)), [currentUser]);
  useEffect(() => localStorage.setItem('users', JSON.stringify(users)), [users]);
  useEffect(() => localStorage.setItem('jobs', JSON.stringify(jobs)), [jobs]);
  useEffect(() => localStorage.setItem('questions', JSON.stringify(questions)), [questions]);
  useEffect(() => localStorage.setItem('messages', JSON.stringify(messages)), [messages]);
  useEffect(() => localStorage.setItem('resumeSubmissions', JSON.stringify(resumeSubmissions)), [resumeSubmissions]);
  useEffect(() => localStorage.setItem('systemConfig', JSON.stringify(systemConfig)), [systemConfig]);

  // --- Auth Actions ---

  const login = (email: string) => {
    const user = users.find(u => u.email === email);
    if (user) {
      if (user.status === UserStatus.BLOCKED) {
        alert("Your account has been blocked by the administrator.");
        return;
      }
      setCurrentUser(user);
    } else {
      alert("User not found. Please register.");
    }
  };

  const logout = () => setCurrentUser(null);

  const register = (name: string, email: string, role: UserRole, year?: string): boolean => {
    if (users.some(u => u.email === email)) return false;
    const newUser: User = { 
      id: Date.now().toString(), 
      name, email, role, year, 
      status: UserStatus.ACTIVE,
      joinedDate: new Date().toISOString().split('T')[0]
    };
    setUsers([...users, newUser]);
    setCurrentUser(newUser);
    return true;
  };

  // --- Admin User Management ---

  const updateUserStatus = (id: string, status: UserStatus) => {
    setUsers(users.map(u => u.id === id ? { ...u, status } : u));
  };

  const updateUserRole = (id: string, role: UserRole) => {
    setUsers(users.map(u => u.id === id ? { ...u, role } : u));
  };

  const deleteUser = (id: string) => {
    setUsers(users.filter(u => u.id !== id));
  };

  // --- Content Management ---

  const addJob = (jobData: Omit<Job, 'id' | 'postedDate'>) => {
    const newJob: Job = {
      ...jobData,
      id: Date.now().toString(),
      postedDate: new Date().toISOString().split('T')[0]
    };
    setJobs([newJob, ...jobs]);
  };

  const deleteJob = (id: string) => {
    setJobs(jobs.filter(j => j.id !== id));
  };

  const addQuestion = (qData: Omit<Question, 'id' | 'status' | 'submittedBy' | 'date'>) => {
    if (!currentUser) return;

    // Basic Duplicate Check
    const isDuplicate = questions.some(q => 
      q.text.toLowerCase().trim() === qData.text.toLowerCase().trim() && 
      q.company.toLowerCase() === qData.company.toLowerCase()
    );

    if (isDuplicate) {
      alert("This exact question already exists in the bank.");
      return;
    }

    const newQ: Question = {
      ...qData,
      id: Date.now().toString(),
      status: currentUser.role === UserRole.ADMIN ? 'APPROVED' : 'PENDING',
      submittedBy: currentUser.id,
      submittedByName: currentUser.name,
      date: new Date().toISOString().split('T')[0]
    };
    setQuestions([newQ, ...questions]);
  };

  const updateQuestionStatus = (id: string, status: 'APPROVED' | 'REJECTED') => {
    setQuestions(questions.map(q => q.id === id ? { ...q, status } : q));
  };

  const deleteQuestion = (id: string) => {
    setQuestions(questions.filter(q => q.id !== id));
  };

  const addNote = (noteData: Omit<Note, 'id' | 'date' | 'authorId' | 'authorName'>) => {
    if (!currentUser) return;
    const newNote: Note = {
      ...noteData,
      id: Date.now().toString(),
      date: new Date().toISOString().split('T')[0],
      authorId: currentUser.id,
      authorName: currentUser.name
    };
    setNotes([newNote, ...notes]);
  };

  // --- Chat & System ---

  const sendMessage = (text: string, channel: string) => {
    if (!currentUser) return;
    const newMsg: ChatMessage = {
      id: Date.now().toString(),
      senderId: currentUser.id,
      senderName: currentUser.name,
      text,
      timestamp: Date.now(),
      channel
    };
    setMessages([...messages, newMsg]);
  };

  const deleteMessage = (id: string) => {
    setMessages(messages.filter(m => m.id !== id));
  };

  const updateResumeContext = (text: string, data: ExtractedResumeData | null) => {
    setResumeContext({ rawText: text, extractedData: data });
  };

  const recordResumeAnalysis = (score: number, role: string) => {
    if (!currentUser) return;
    const newSub: ResumeSubmission = {
      id: Date.now().toString(),
      userId: currentUser.id,
      userName: currentUser.name,
      score,
      role,
      date: new Date().toISOString().split('T')[0],
      status: 'REVIEWED'
    };
    setResumeSubmissions([newSub, ...resumeSubmissions]);
  };

  const updateSystemConfig = (config: Partial<SystemConfig>) => {
    setSystemConfig({ ...systemConfig, ...config });
  };

  const channels: Channel[] = [
    { id: 'general', name: 'General Lounge', description: 'Hangout and chat.', type: 'PUBLIC' },
    { id: 'interview', name: 'Interview Prep', description: 'Mock interviews.', type: 'PUBLIC' },
    { id: 'announcements', name: 'Announcements', description: 'Admin updates.', type: 'ANNOUNCEMENT' },
  ];

  return (
    <AppContext.Provider value={{
      currentUser, users, jobs, questions, notes, messages, channels, resumeContext, resumeSubmissions, systemConfig,
      login, logout, register, 
      updateUserStatus, updateUserRole, deleteUser,
      addJob, deleteJob,
      addQuestion, updateQuestionStatus, deleteQuestion,
      addNote, 
      sendMessage, deleteMessage,
      updateResumeContext, recordResumeAnalysis, updateSystemConfig
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

import mongoose from 'mongoose';

const userSchema = new mongoose.Schema({
  name: { type: String, required: true },
  email: { type: String, required: true, unique: true },
  password: { type: String, required: true },
  role: { 
    type: String, 
    enum: ['STUDENT', 'ADMIN', 'MODERATOR'], 
    default: 'STUDENT' 
  },
  status: { 
    type: String, 
    enum: ['ACTIVE', 'BLOCKED'], 
    default: 'ACTIVE' 
  },
  year: String,
  joinedDate: { type: Date, default: Date.now }
});

export const User = mongoose.model('User', userSchema);

import mongoose from 'mongoose';

const resumeSchema = new mongoose.Schema({
