  type: { type: String, enum: ['Full-time', 'Internship', 'Part-time'] },
  description: String,
  applicationLink: String,
  category: { type: String, enum: ['On-Campus', 'Off-Campus', 'Remote'] },
  deadline: String,
  postedDate: { type: String, default: () => new Date().toLocaleDateString() }, // Store as string for UI simplicity
  postedBy: { type: mongoose.Schema.Types.ObjectId, ref: 'User' },
  createdAt: { type: Date, default: Date.now }
});

export const Job = mongoose.model('Job', jobSchema);

import mongoose from 'mongoose';

const chatMessageSchema = new mongoose.Schema({
  senderId: { type: mongoose.Schema.Types.ObjectId, ref: 'User', required: true },
  senderName: { type: String, required: true },
  text: { type: String, required: true },
  channel: { type: String, required: true, index: true },
  timestamp: { type: Number, default: Date.now },
  isFlagged: { type: Boolean, default: false }
});

export const ChatMessage = mongoose.model('ChatMessage', chatMessageSchema);

import express from 'express';
import mongoose from 'mongoose';
import cors from 'cors';
import dotenv from 'dotenv';
import multer from 'multer';
import pdfParse from 'pdf-parse';
import crypto from 'crypto';
import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';

import { User } from './models/User';
import { Resume } from './models/Resume';
import { Question } from './models/Question';
import { Job } from './models/Job';
import { ChatMessage } from './models/ChatMessage';
import { analyzeResumeText } from './services/aiService';

dotenv.config();

const app = express();
app.use(cors());
app.use(express.json());

// MongoDB Connection (Use 127.0.0.1 to avoid localhost IPv6 issues)
const MONGO_URI = process.env.MONGO_URI || 'mongodb://127.0.0.1:27017/campus-media';
mongoose.connect(MONGO_URI)
  .then(() => console.log('✅ MongoDB Connected'))
  .catch(err => {
    console.error('❌ MongoDB Connection Error:', err);
    process.exit(1);
  });

// Middleware
const upload = multer({ storage: multer.memoryStorage() });

const auth = async (req: any, res: any, next: any) => {
  try {
    const token = req.header('Authorization')?.replace('Bearer ', '');
    if (!token) throw new Error();
    const decoded: any = jwt.verify(token, process.env.JWT_SECRET || 'secret');
    req.user = decoded;
    next();
  } catch (err) {
    res.status(401).send({ error: 'Please authenticate.' });
  }
};

// --- AUTH ROUTES ---
app.post('/api/auth/register', async (req, res) => {
  try {
    const { name, email, password, role, year } = req.body;
    const existingUser = await User.findOne({ email });
    if (existingUser) return res.status(400).send({ error: 'Email already exists' });

    const hashedPassword = await bcrypt.hash(password, 8);
    const user = new User({ name, email, password: hashedPassword, role, year });
    await user.save();

    // Return user without password
    const userObj = user.toObject();
    // @ts-ignore
    delete userObj.password;

    const token = jwt.sign({ id: user._id, role: user.role }, process.env.JWT_SECRET || 'secret');
    res.status(201).send({ user: userObj, token });
  } catch (e: any) {
    res.status(400).send({ error: e.message });
  }
});

app.post('/api/auth/login', async (req, res) => {
  try {
    const { email, password } = req.body;
    const user = await User.findOne({ email });
    if (!user) throw new Error('User not found');

    const isMatch = await bcrypt.compare(password, user.password);
    if (!isMatch) throw new Error('Invalid credentials');

    const token = jwt.sign({ id: user._id, role: user.role }, process.env.JWT_SECRET || 'secret');

    const userObj = user.toObject();
    // @ts-ignore
    delete userObj.password;

    res.send({ user: userObj, token });
  } catch (e) {
    res.status(400).send({ error: 'Login failed' });
  }
});

// --- RESUME ROUTES ---
app.post('/api/resume/analyze', auth, upload.single('resume'), async (req: any, res) => {
  try {
    const { targetRole, experienceLevel } = req.body;
    if (!req.file) throw new Error('No file uploaded');

    const data = await pdfParse(req.file.buffer);
    const rawText = data.text;

    // Duplicate Check
    const contentHash = crypto.createHash('sha256').update(rawText).digest('hex');
    const existing = await Resume.findOne({ contentHash, userId: req.user.id });

    if (existing) {
      return res.send(existing.analysis);
    }

    // AI Analysis
    const analysis = await analyzeResumeText(rawText, targetRole, experienceLevel);

    const resume = new Resume({
      userId: req.user.id,
      rawText,
      contentHash,
      targetRole,
      analysis
    });
    await resume.save();

    res.send(analysis);
  } catch (e: any) {
    console.error("Resume Error:", e);
    res.status(500).send({ error: e.message });
  }
});

// --- QUESTION BANK ROUTES ---
app.get('/api/questions', async (req, res) => {
  try {
    const questions = await Question.find().sort({ date: -1 });
    // Normalize _id to id for frontend
    const formatted = questions.map(q => ({ ...q.toObject(), id: q._id }));
    res.send(formatted);
  } catch (e) {
    res.status(500).send(e);
  }
});

app.post('/api/questions', auth, async (req: any, res) => {
  try {
    const { text, company, role, difficulty } = req.body;
    const user = await User.findById(req.user.id);
    const question = new Question({
      text, company, role, difficulty,
      submittedBy: req.user.id,
      submittedByName: user?.name || 'Anonymous',
      status: req.user.role === 'ADMIN' ? 'APPROVED' : 'PENDING'
    });
    await question.save();
    res.status(201).send({ ...question.toObject(), id: question._id });
  } catch (e) {
    res.status(400).send(e);
  }
});

app.patch('/api/questions/:id/status', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    const question = await Question.findByIdAndUpdate(req.params.id, { status: req.body.status }, { new: true });
    if (question) res.send({ ...question.toObject(), id: question._id });
    else res.status(404).send();
  } catch (e) {
    res.status(400).send(e);
  }
});

app.delete('/api/questions/:id', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    await Question.findByIdAndDelete(req.params.id);
    res.send({ success: true });
  } catch (e) {
    res.status(500).send(e);
  }
});

// --- JOB ROUTES ---
app.get('/api/jobs', async (req, res) => {
  try {
    const jobs = await Job.find().sort({ createdAt: -1 });
    const formatted = jobs.map(j => ({ ...j.toObject(), id: j._id }));
    res.send(formatted);
  } catch (e) { res.status(500).send(e); }
});

app.post('/api/jobs', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    const job = new Job({ ...req.body, postedBy: req.user.id });
    await job.save();
    res.status(201).send({ ...job.toObject(), id: job._id });
  } catch (e) { res.status(400).send(e); }
});

app.delete('/api/jobs/:id', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    await Job.findByIdAndDelete(req.params.id);
    res.send({ success: true });
  } catch (e) { res.status(500).send(e); }
});

// --- CHAT ROUTES ---
app.get('/api/chat/:channel', async (req, res) => {
  try {
    const messages = await ChatMessage.find({ channel: req.params.channel }).sort({ timestamp: 1 }).limit(100);
    const formatted = messages.map(m => ({ ...m.toObject(), id: m._id }));
    res.send(formatted);
  } catch (e) { res.status(500).send(e); }
});

app.post('/api/chat', auth, async (req: any, res) => {
  try {
    const { text, channel } = req.body;
    const user = await User.findById(req.user.id);

    // Simple Profanity Filter (Example)
    const bannedWords = ['badword', 'spam']; 
    const isFlagged = bannedWords.some(word => text.toLowerCase().includes(word));

    const message = new ChatMessage({
      senderId: req.user.id,
      senderName: user?.name,
      text,
      channel,
      isFlagged
    });
    await message.save();
    res.status(201).send({ ...message.toObject(), id: message._id });
  } catch (e) { res.status(400).send(e); }
});

app.delete('/api/chat/:id', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    await ChatMessage.findByIdAndDelete(req.params.id);
    res.send({ success: true });
  } catch (e) { res.status(500).send(e); }
});

// --- USER MANAGEMENT (ADMIN) ---
app.get('/api/users', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    const users = await User.find({}, '-password'); // Exclude password
    const formatted = users.map(u => ({ ...u.toObject(), id: u._id }));
    res.send(formatted);
  } catch (e) { res.status(500).send(e); }
});

app.patch('/api/users/:id/status', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    const user = await User.findByIdAndUpdate(req.params.id, { status: req.body.status }, { new: true });
    res.send(user);
  } catch (e) { res.status(400).send(e); }
});

// Start Server
const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`🚀 Server running on port ${PORT}`));

import React, { createContext, useContext, useState, ReactNode, useEffect, useCallback } from 'react';
import api from '../services/api';
import { User, Job, Question, Note, UserRole, UserStatus, ChatMessage, Channel, ExtractedResumeData, ResumeSubmission, SystemConfig } from '../types';

interface ResumeContextState {
  rawText: string;
  extractedData: ExtractedResumeData | null;
}

interface AppContextType {
  currentUser: User | null;
  users: User[];
  jobs: Job[];
  questions: Question[];
  notes: Note[];
  messages: ChatMessage[];
  channels: Channel[];
  resumeContext: ResumeContextState;
  resumeSubmissions: ResumeSubmission[];
  systemConfig: SystemConfig;

  login: (email: string, password?: string) => Promise<void>;
  logout: () => void;
  register: (name: string, email: string, role: UserRole, year?: string, password?: string) => Promise<boolean>;

  addQuestion: (question: any) => void;
  updateQuestionStatus: (id: string, status: string) => void;
  updateResumeContext: (text: string, data: any) => void;

  updateUserStatus: (id: string, status: string) => void;
  updateUserRole: (id: string, role: string) => void;
  deleteUser: (id: string) => void;
  addJob: (job: any) => void;
  deleteJob: (id: string) => void;
  deleteQuestion: (id: string) => void;
  addNote: (note: any) => void;
  sendMessage: (text: string, channelId: string) => void;
  deleteMessage: (id: string) => void;
  recordResumeAnalysis: (data: any) => void;
  updateSystemConfig: (config: any) => void;
  fetchMessages: (channelId: string) => void;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [jobs, setJobs] = useState<Job[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [notes, setNotes] = useState<Note[]>([]);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [resumeSubmissions, setResumeSubmissions] = useState<ResumeSubmission[]>([]);

  const [resumeContext, setResumeContext] = useState<ResumeContextState>({ rawText: '', extractedData: null });
  const [systemConfig, setSystemConfig] = useState<SystemConfig>({
      announcement: "Welcome to Campus Media v1.0",
      allowSignups: true,
      maintenanceMode: false,
      interviewCategories: []
  });

  const [channels, setChannels] = useState<Channel[]>([
      { id: 'general', name: 'General', description: 'General Discussion', type: 'PUBLIC' },
      { id: 'interview-prep', name: 'Interview Prep', description: 'Mock interviews & tips', type: 'PUBLIC' },
      { id: 'jobs', name: 'Jobs', description: 'Job openings & referrals', type: 'PUBLIC' }
  ]);

  // Load Auth from LocalStorage
  useEffect(() => {
    const token = localStorage.getItem('token');
    const userStr = localStorage.getItem('currentUser');
    if (token && userStr) {
      setCurrentUser(JSON.parse(userStr));
    }
  }, []);

  // Fetch Data when User is Logged In
  const fetchData = useCallback(async () => {
    if (!currentUser) return;

    try {
      const [qRes, jRes] = await Promise.all([
        api.get('/questions'),
        api.get('/jobs')
      ]);
      setQuestions(qRes.data);
      setJobs(jRes.data);

      if (currentUser.role === 'ADMIN') {
        const uRes = await api.get('/users');
        setUsers(uRes.data);
      }

      // Load initial chat for general
      fetchMessages('general');

    } catch (e) {
      console.error("Error fetching initial data", e);
    }
  }, [currentUser]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const fetchMessages = async (channelId: string) => {
    try {
      const res = await api.get(`/chat/${channelId}`);
      setMessages(res.data);
    } catch (e) { console.error(e); }
  };

  const login = async (email: string, password = 'password123') => {
    try {
      const res = await api.post('/auth/login', { email, password });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('currentUser', JSON.stringify(res.data.user));
      setCurrentUser(res.data.user);
    } catch (e) {
      alert("Login Failed. Please check credentials.");
      throw e;
    }
  };

  const register = async (name: string, email: string, role: UserRole, year?: string, password = 'password123') => {
    try {
      const res = await api.post('/auth/register', { name, email, password, role, year });
      localStorage.setItem('token', res.data.token);
      localStorage.setItem('currentUser', JSON.stringify(res.data.user));
      setCurrentUser(res.data.user);
      return true;
    } catch (e) {
      alert("Registration Failed.");
      return false;
    }
  };

  const logout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('currentUser');
    setCurrentUser(null);
    setQuestions([]);
    setJobs([]);
    setMessages([]);
  };

  // --- ACTIONS ---

  const addQuestion = async (qData: any) => {
    try {
      const res = await api.post('/questions', qData);
      setQuestions(prev => [res.data, ...prev]);
    } catch (e) { alert("Failed to submit question"); }
  };

  const updateQuestionStatus = async (id: string, status: string) => {
    try {
      const res = await api.patch(`/questions/${id}/status`, { status });
      setQuestions(questions.map(q => q.id === id ? res.data : q));
    } catch (e) { alert("Action failed"); }
  };

  const deleteQuestion = async (id: string) => {
    try {
      await api.delete(`/questions/${id}`);
      setQuestions(questions.filter(q => q.id !== id));
    } catch (e) { alert("Delete failed"); }
  };

  const addJob = async (job: any) => {
    try {
      const res = await api.post('/jobs', job);
      setJobs(prev => [res.data, ...prev]);
    } catch (e) { alert("Failed to post job"); }
  };

  const deleteJob = async (id: string) => {
    try {
      await api.delete(`/jobs/${id}`);
      setJobs(jobs.filter(j => j.id !== id));
    } catch (e) { alert("Delete failed"); }
  };

  const sendMessage = async (text: string, channelId: string) => {
    try {
      const res = await api.post('/chat', { text, channel: channelId });
      setMessages(prev => [...prev, res.data]);
    } catch (e) { alert("Message failed"); }
  };

  const deleteMessage = async (id: string) => {
    try {
      await api.delete(`/chat/${id}`);
      setMessages(messages.filter(m => m.id !== id));
    } catch (e) { alert("Delete failed"); }
  };

  const updateUserStatus = async (id: string, status: string) => {
    try {
      const res = await api.patch(`/users/${id}/status`, { status });
      setUsers(users.map(u => u.id === id ? { ...u, status: res.data.status } : u));
    } catch (e) { alert("Update failed"); }
  };

  const deleteUser = (id: string) => { 
    // Typically backend API for delete user
    setUsers(users.filter(u => u.id !== id)); 
  };

  const updateResumeContext = (text: string, data: any) => {
    setResumeContext({ rawText: text, extractedData: data });
  };

  // Placeholders
  const updateUserRole = (id: string, role: string) => {}; 
  const addNote = (note: any) => {
     setNotes(prev => [...prev, { ...note, id: Date.now().toString(), authorId: currentUser?.id, authorName: currentUser?.name, date: new Date().toLocaleDateString() }]);
  };
  const recordResumeAnalysis = (data: any) => {};
  const updateSystemConfig = (config: any) => { setSystemConfig(prev => ({...prev, ...config})); };

  return (
    <AppContext.Provider value={{
      currentUser, users, jobs, questions, notes, messages, channels, resumeContext, resumeSubmissions, systemConfig,
      login, logout, register, 
      addQuestion, updateQuestionStatus, deleteQuestion,
      addJob, deleteJob,
      sendMessage, deleteMessage, fetchMessages,
      updateUserStatus, updateUserRole, deleteUser, 
      updateResumeContext, addNote, recordResumeAnalysis, updateSystemConfig
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

import React, { useState, useEffect, useRef } from 'react';
import { useApp } from '../context/AppContext';
import { Send, Users, Hash, MessageCircle } from 'lucide-react';
import { UserRole } from '../types';

export const MentorshipChat: React.FC = () => {
  const { currentUser, channels, messages, sendMessage, fetchMessages } = useApp();
  const [activeChannelId, setActiveChannelId] = useState<string>('general');
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const activeChannel = channels.find(c => c.id === activeChannelId);
  const channelMessages = messages.filter(m => m.channel === activeChannelId);

  useEffect(() => {
    // Fetch messages when channel changes
    fetchMessages(activeChannelId);
  }, [activeChannelId]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [channelMessages]);

  const handleSend = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputText.trim()) {
      sendMessage(inputText, activeChannelId);
      setInputText('');
    }
  };

  const getRoleBadge = (msgSenderId: string) => {
    if (currentUser?.id === msgSenderId) {
        return <span className="text-[10px] bg-indigo-100 text-indigo-700 px-1.5 py-0.5 rounded ml-2 font-bold">YOU</span>;
    }
    return null;
  };

  return (
    <div className="flex h-[calc(100vh-8rem)] bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
      {/* Sidebar Channels */}
      <div className="w-64 bg-slate-50 border-r border-slate-200 flex flex-col">
        <div className="p-4 border-b border-slate-200">
          <h2 className="font-bold text-slate-800 flex items-center gap-2">
            <Users size={20} className="text-indigo-600"/> Mentorship Hub
          </h2>
          <p className="text-xs text-slate-500 mt-1">Connect with seniors & peers</p>
        </div>
        <div className="flex-1 overflow-y-auto p-3 space-y-1">
          {channels.map(channel => (
            <button
              key={channel.id}
              onClick={() => setActiveChannelId(channel.id)}
              className={`w-full flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium transition-colors ${
                activeChannelId === channel.id 
                  ? 'bg-indigo-100 text-indigo-700' 
                  : 'text-slate-600 hover:bg-slate-100'
              }`}
            >
              <Hash size={18} className="opacity-50" />
              {channel.name}
            </button>
          ))}
        </div>
      </div>

      {/* Chat Area */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <div className="p-4 border-b border-slate-200 flex justify-between items-center bg-white">
          <div>
             <h3 className="font-bold text-slate-800 flex items-center gap-2">
               <Hash size={20} className="text-slate-400"/> {activeChannel?.name}
             </h3>
             <p className="text-xs text-slate-500">{activeChannel?.description}</p>
          </div>
        </div>

        {/* Messages */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-white">
          {channelMessages.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-slate-400">
              <MessageCircle size={48} className="mb-2 opacity-20" />
              <p>No messages yet. Start the conversation!</p>
            </div>
          ) : (
            channelMessages.map(msg => (
              <div key={msg.id} className={`flex flex-col ${msg.senderId === currentUser?.id ? 'items-end' : 'items-start'}`}>
                 <div className="flex items-baseline gap-2 mb-1">
                    <span className="text-xs font-bold text-slate-700">{msg.senderName}</span>
                    <span className="text-[10px] text-slate-400">
                       {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                    </span>
                    {getRoleBadge(msg.senderId)}
                 </div>
                 <div className={`max-w-[80%] px-4 py-2 rounded-2xl text-sm ${
                   msg.senderId === currentUser?.id 
                     ? 'bg-indigo-600 text-white rounded-br-none' 
                     : 'bg-slate-100 text-slate-800 rounded-bl-none'
                 }`}>
                   {msg.text}
                 </div>
              </div>
            ))
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input */}
        <form onSubmit={handleSend} className="p-4 border-t border-slate-200 bg-slate-50">
          <div className="flex gap-2">
            <input
              type="text"
              placeholder={`Message #${activeChannel?.name}...`}
              className="flex-1 p-3 border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-indigo-500"
              value={inputText}
              onChange={(e) => setInputText(e.target.value)}
            />
            <button 
              type="submit"
              disabled={!inputText.trim()}
              className="bg-indigo-600 text-white p-3 rounded-xl hover:bg-indigo-700 disabled:opacity-50 transition-colors"
            >
              <Send size={20} />
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

