import express from 'express';
import mongoose from 'mongoose';
import cors from 'cors';
import dotenv from 'dotenv';
import multer from 'multer';
import pdfParse from 'pdf-parse';
import crypto from 'crypto';
import jwt from 'jsonwebtoken';
import bcrypt from 'bcryptjs';

import { User } from './models/User';
import { Resume } from './models/Resume';
import { Question } from './models/Question';
import { Job } from './models/Job';
import { ChatMessage } from './models/ChatMessage';
import { analyzeResumeText } from './services/aiService';

dotenv.config();

const app = express();
app.use(cors());
app.use(express.json());

// MongoDB Connection (Use 127.0.0.1 to avoid localhost IPv6 issues)
const MONGO_URI = process.env.MONGO_URI || 'mongodb://127.0.0.1:27017/campus-media';
mongoose.connect(MONGO_URI)
  .then(() => console.log('✅ MongoDB Connected'))
  .catch(err => {
    console.error('❌ MongoDB Connection Error:', err);
    (process as any).exit(1);
  });

// Middleware
const upload = multer({ storage: multer.memoryStorage() });

const auth = async (req: any, res: any, next: any) => {
  try {
    const token = req.header('Authorization')?.replace('Bearer ', '');
    if (!token) throw new Error();
    const decoded: any = jwt.verify(token, process.env.JWT_SECRET || 'secret');
    req.user = decoded;
    next();
  } catch (err) {
    res.status(401).send({ error: 'Please authenticate.' });
  }
};

// --- AUTH ROUTES ---
app.post('/api/auth/register', async (req, res) => {
  try {
    const { name, email, password, role, year } = req.body;
    const existingUser = await User.findOne({ email });
    if (existingUser) return res.status(400).send({ error: 'Email already exists' });

    const hashedPassword = await bcrypt.hash(password, 8);
    const user = new User({ name, email, password: hashedPassword, role, year });
    await user.save();

    // Return user without password
    const userObj = user.toObject();
    // @ts-ignore
    delete userObj.password;

    const token = jwt.sign({ id: user._id, role: user.role }, process.env.JWT_SECRET || 'secret');
    res.status(201).send({ user: userObj, token });
  } catch (e: any) {
    res.status(400).send({ error: e.message });
  }
});

app.post('/api/auth/login', async (req, res) => {
  try {
    const { email, password } = req.body;
    const user = await User.findOne({ email });
    if (!user) throw new Error('User not found');

    const isMatch = await bcrypt.compare(password, user.password);
    if (!isMatch) throw new Error('Invalid credentials');

    const token = jwt.sign({ id: user._id, role: user.role }, process.env.JWT_SECRET || 'secret');

    const userObj = user.toObject();
    // @ts-ignore
    delete userObj.password;

    res.send({ user: userObj, token });
  } catch (e) {
    res.status(400).send({ error: 'Login failed' });
  }
});

// --- RESUME ROUTES ---
app.post('/api/resume/analyze', auth, upload.single('resume'), async (req: any, res) => {
  try {
    const { targetRole, experienceLevel } = req.body;
    if (!req.file) throw new Error('No file uploaded');

    const data = await pdfParse(req.file.buffer);
    const rawText = data.text;

    // Duplicate Check
    const contentHash = crypto.createHash('sha256').update(rawText).digest('hex');
    const existing = await Resume.findOne({ contentHash, userId: req.user.id });

    if (existing) {
      return res.send(existing.analysis);
    }

    // AI Analysis
    const analysis = await analyzeResumeText(rawText, targetRole, experienceLevel);

    const resume = new Resume({
      userId: req.user.id,
      rawText,
      contentHash,
      targetRole,
      analysis
    });
    await resume.save();

    res.send(analysis);
  } catch (e: any) {
    console.error("Resume Error:", e);
    res.status(500).send({ error: e.message });
  }
});

// --- QUESTION BANK ROUTES ---
app.get('/api/questions', async (req, res) => {
  try {
    const questions = await Question.find().sort({ date: -1 });
    // Normalize _id to id for frontend
    const formatted = questions.map(q => ({ ...q.toObject(), id: q._id }));
    res.send(formatted);
  } catch (e) {
    res.status(500).send(e);
  }
});

app.post('/api/questions', auth, async (req: any, res) => {
  try {
    const { text, company, role, difficulty } = req.body;
    const user = await User.findById(req.user.id);
    const question = new Question({
      text, company, role, difficulty,
      submittedBy: req.user.id,
      submittedByName: user?.name || 'Anonymous',
      status: req.user.role === 'ADMIN' ? 'APPROVED' : 'PENDING'
    });
    await question.save();
    res.status(201).send({ ...question.toObject(), id: question._id });
  } catch (e) {
    res.status(400).send(e);
  }
});

app.patch('/api/questions/:id/status', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    const question = await Question.findByIdAndUpdate(req.params.id, { status: req.body.status }, { new: true });
    if (question) res.send({ ...question.toObject(), id: question._id });
    else res.status(404).send();
  } catch (e) {
    res.status(400).send(e);
  }
});

app.delete('/api/questions/:id', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    await Question.findByIdAndDelete(req.params.id);
    res.send({ success: true });
  } catch (e) {
    res.status(500).send(e);
  }
});

// --- JOB ROUTES ---
app.get('/api/jobs', async (req, res) => {
  try {
    const jobs = await Job.find().sort({ createdAt: -1 });
    const formatted = jobs.map(j => ({ ...j.toObject(), id: j._id }));
    res.send(formatted);
  } catch (e) { res.status(500).send(e); }
});

app.post('/api/jobs', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    const job = new Job({ ...req.body, postedBy: req.user.id });
    await job.save();
    res.status(201).send({ ...job.toObject(), id: job._id });
  } catch (e) { res.status(400).send(e); }
});

app.delete('/api/jobs/:id', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    await Job.findByIdAndDelete(req.params.id);
    res.send({ success: true });
  } catch (e) { res.status(500).send(e); }
});

// --- CHAT ROUTES ---
app.get('/api/chat/:channel', async (req, res) => {
  try {
    const messages = await ChatMessage.find({ channel: req.params.channel }).sort({ timestamp: 1 }).limit(100);
    const formatted = messages.map(m => ({ ...m.toObject(), id: m._id }));
    res.send(formatted);
  } catch (e) { res.status(500).send(e); }
});

app.post('/api/chat', auth, async (req: any, res) => {
  try {
    const { text, channel } = req.body;
    const user = await User.findById(req.user.id);

    // Simple Profanity Filter (Example)
    const bannedWords = ['badword', 'spam']; 
    const isFlagged = bannedWords.some(word => text.toLowerCase().includes(word));

    const message = new ChatMessage({
      senderId: req.user.id,
      senderName: user?.name,
      text,
      channel,
      isFlagged
    });
    await message.save();
    res.status(201).send({ ...message.toObject(), id: message._id });
  } catch (e) { res.status(400).send(e); }
});

app.delete('/api/chat/:id', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    await ChatMessage.findByIdAndDelete(req.params.id);
    res.send({ success: true });
  } catch (e) { res.status(500).send(e); }
});

// --- USER MANAGEMENT (ADMIN) ---
app.get('/api/users', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    const users = await User.find({}, '-password'); // Exclude password
    const formatted = users.map(u => ({ ...u.toObject(), id: u._id }));
    res.send(formatted);
  } catch (e) { res.status(500).send(e); }
});

app.patch('/api/users/:id/status', auth, async (req: any, res) => {
  try {
    if (req.user.role !== 'ADMIN') return res.status(403).send('Unauthorized');
    const user = await User.findByIdAndUpdate(req.params.id, { status: req.body.status }, { new: true });
    res.send(user);
  } catch (e) { res.status(400).send(e); }
});

// Start Server
const PORT = process.env.PORT || 5000;
app.listen(PORT, () => console.log(`🚀 Server running on port ${PORT}`));

import { GoogleGenAI, Type } from "@google/genai";
import dotenv from 'dotenv';

dotenv.config();

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzeResumeText = async (text: string, role: string, level: string) => {
  const model = "gemini-2.5-flash";
  const prompt = `
    Analyze this resume for a ${role} (${level}) role.
    Strictly extract data and provide scoring.
    RESUME TEXT: "${text.slice(0, 30000)}"
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          extractedData: {
            type: Type.OBJECT,
            properties: {
              personalInfo: {
                 type: Type.OBJECT,
                 properties: {
                    name: { type: Type.STRING },
                    email: { type: Type.STRING },
                    links: { type: Type.ARRAY, items: { type: Type.STRING } }
                 }
              },
              keySkills: { type: Type.ARRAY, items: { type: Type.STRING } },
              projects: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    techStack: { type: Type.ARRAY, items: { type: Type.STRING } },
                    description: { type: Type.STRING }
                  }
                }
              },
              workExperience: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    role: { type: Type.STRING },
                    company: { type: Type.STRING },
                    duration: { type: Type.STRING },
                  }
                }
              },
            }
          },
          score: { type: Type.NUMBER },
          atsCompatibility: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
          missingSkills: { type: Type.ARRAY, items: { type: Type.STRING } },
          optimizedPoints: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
