import { GoogleGenAI, Type } from "@google/genai";
import dotenv from 'dotenv';

dotenv.config();

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean JSON string if model adds markdown formatting
const cleanAndParseJSON = (text: string) => {
  try {
    // Remove markdown code blocks if present
    const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleaned);
  } catch (e) {
    console.error("JSON Parse Error:", e);
    console.error("Raw Text:", text);
    throw new Error("Failed to parse AI response");
  }
};

export const analyzeResumeText = async (text: string, role: string, level: string) => {
  const model = "gemini-2.5-flash";
  const prompt = `
    You are an expert ATS (Applicant Tracking System) and Career Coach. 
    Analyze the following resume for a ${role} position at ${level} level.

    TASK:
    1. Extract key data.
    2. Score the resume from 0-100 based on relevance to the role and ATS formatting best practices.
    3. Provide concrete examples of how to rewrite bullet points to be impact-driven (Action Verb + Task + Result).
    4. Identify missing hard skills critical for this specific role.

    RESUME TEXT: 
    "${text.slice(0, 30000)}"
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          extractedData: {
            type: Type.OBJECT,
            properties: {
              personalInfo: {
                 type: Type.OBJECT,
                 properties: {
                    name: { type: Type.STRING },
                    email: { type: Type.STRING },
                    links: { type: Type.ARRAY, items: { type: Type.STRING } }
                 }
              },
              keySkills: { type: Type.ARRAY, items: { type: Type.STRING } },
              projects: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    techStack: { type: Type.ARRAY, items: { type: Type.STRING } },
                    description: { type: Type.STRING }
                  }
                }
              },
              workExperience: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    role: { type: Type.STRING },
                    company: { type: Type.STRING },
                    duration: { type: Type.STRING },
                  }
                }
              },
            }
          },
          score: { type: Type.NUMBER },
          atsCompatibility: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
          missingSkills: { type: Type.ARRAY, items: { type: Type.STRING } },
          optimizedPoints: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                original: { type: Type.STRING },
                optimized: { type: Type.STRING },
                reason: { type: Type.STRING }
              }
            }
          },
          summary: { type: Type.STRING }
        }
      },
    },
  });

  if (!response.text) throw new Error("AI Error");
  return cleanAndParseJSON(response.text);
};

export const generateFeedback = async (transcript: string) => {
  const model = "gemini-2.5-flash";
  const prompt = `
    You are a Senior Technical Interviewer. Analyze the following voice interview transcript.
    TRANSCRIPT:
    "${transcript}"

    Provide a strict performance report.
    - Identify exactly where the candidate failed to answer correctly.
    - Provide "Corrected Answers" for mistakes.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          mistakes: { type: Type.ARRAY, items: { type: Type.STRING } },
          improvements: { type: Type.ARRAY, items: { type: Type.STRING } },
          communicationTips: { type: Type.ARRAY, items: { type: Type.STRING } },
          technicalTips: { type: Type.ARRAY, items: { type: Type.STRING } },
          correctedAnswers: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                originalAnswer: { type: Type.STRING },
                idealAnswer: { type: Type.STRING },
              },
            },
          },
          roadmap: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
      },
    },
  });

  if (!response.text) throw new Error("No feedback generated");
  return cleanAndParseJSON(response.text);
};

export const generateRoadmap = async (currentSkills: string[], targetDomain: string) => {
  const model = "gemini-2.5-flash";
  const prompt = `
    Create a detailed, step-by-step 6-Stage Learning Roadmap for a student targeting the domain: "${targetDomain}".
    Current Skills: ${currentSkills.join(", ")}.

    Instructions:
    - If current skills are empty, assume beginner.
    - Stage 1 should be foundations, Stage 6 should be mastery/advanced projects.
    - Provide resource keywords (e.g. "MDN Docs", "Coursera", "Official Docs").
    - Time estimate should be realistic (e.g., "2 weeks").
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          targetDomain: { type: Type.STRING },
          stages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stageName: { type: Type.STRING },
                description: { type: Type.STRING },
                items: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      topic: { type: Type.STRING },
                      reason: { type: Type.STRING },
                      timeEstimate: { type: Type.STRING },
                      difficulty: { type: Type.STRING, enum: ["Easy", "Medium", "Hard"] },
                      resources: { type: Type.ARRAY, items: { type: Type.STRING } }
                    }
                  }
                }
              }
            }
          }
        }
      },
    },
  });

  if (!response.text) throw new Error("Roadmap generation failed");
  return cleanAndParseJSON(response.text);
};

import React, { useState } from 'react';
import { Upload, FileText, CheckCircle, AlertTriangle, Lightbulb, TrendingUp, Sparkles, ArrowRight, XCircle } from 'lucide-react';
import api from '../services/api';
import { ResumeAnalysis } from '../types';
import { useApp } from '../context/AppContext';

export const ResumeAnalyzer: React.FC = () => {
  const { updateResumeContext } = useApp();
  const [role, setRole] = useState('');
  const [level, setLevel] = useState('Entry-Level');
  const [file, setFile] = useState<File | null>(null);
  const [analysis, setAnalysis] = useState<ResumeAnalysis | null>(null);
  const [loading, setLoading] = useState(false);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files?.[0]) setFile(e.target.files[0]);
  };

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file || !role) {
        alert("Please select a file and enter a role.");
        return;
    }

    setLoading(true);
    try {
      const formData = new FormData();
      formData.append('resume', file);
      formData.append('targetRole', role);
      formData.append('experienceLevel', level);

      const res = await api.post('/resume/analyze', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });

      setAnalysis(res.data);
      // Store raw text in context for Interview
      updateResumeContext(res.data.extractedData.rawText || "Parsed Content", res.data.extractedData);
    } catch (error) {
      console.error("Analysis failed", error);
      alert("Failed to analyze resume. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="h-[calc(100vh-6rem)] grid grid-cols-1 lg:grid-cols-12 gap-6">
      <div className="lg:col-span-4 flex flex-col gap-6 overflow-y-auto pr-2">
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h2 className="text-xl font-bold text-slate-800 mb-4 flex items-center gap-2">
            <Upload className="text-indigo-600" /> Resume Setup
          </h2>
