import { GoogleGenAI, Type } from "@google/genai";
import { InterviewFeedback, Roadmap, ResumeAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanAndParseJSON = (text: string) => {
  try {
    const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleaned);
  } catch (e) {
    console.error("JSON Parse Error:", e, "Raw:", text);
    throw new Error("Failed to parse AI response");
  }
};

export const analyzeResumeText = async (text: string, role: string, level: string): Promise<ResumeAnalysis> => {
  const prompt = `
    You are an expert ATS (Applicant Tracking System) and Career Coach. 
    Analyze the following resume for a ${role} position at ${level} level.
    TASK:
    1. Extract key data.
    2. Score the resume (0-100).
    3. Provide impact-driven bullet point rewrites.
    4. Identify missing critical hard skills.
    RESUME TEXT: "${text.slice(0, 30000)}"
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          extractedData: {
            type: Type.OBJECT,
            properties: {
              personalInfo: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, email: { type: Type.STRING }, links: { type: Type.ARRAY, items: { type: Type.STRING } } } },
              keySkills: { type: Type.ARRAY, items: { type: Type.STRING } },
              projects: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              workExperience: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { role: { type: Type.STRING }, company: { type: Type.STRING } } } }
            }
          },
          score: { type: Type.NUMBER },
          atsCompatibility: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
          missingSkills: { type: Type.ARRAY, items: { type: Type.STRING } },
          optimizedPoints: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { original: { type: Type.STRING }, optimized: { type: Type.STRING }, reason: { type: Type.STRING } } } },
          summary: { type: Type.STRING }
        }
      }
    }
  });

  return cleanAndParseJSON(response.text || "{}");
};

export const generateFeedbackFromTranscript = async (transcript: string): Promise<InterviewFeedback> => {
  const prompt = `Evaluate this interview: "${transcript}". Provide score, mistakes, and ideal answers.`;
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          mistakes: { type: Type.ARRAY, items: { type: Type.STRING } },
          improvements: { type: Type.ARRAY, items: { type: Type.STRING } },
          communicationTips: { type: Type.ARRAY, items: { type: Type.STRING } },
          correctedAnswers: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { question: { type: Type.STRING }, originalAnswer: { type: Type.STRING }, idealAnswer: { type: Type.STRING } } } }
        }
      }
    }
  });
  return cleanAndParseJSON(response.text || "{}");
};

export const generateRoadmap = async (currentSkills: string[], targetDomain: string): Promise<Roadmap> => {
  const prompt = `Create a 6-stage roadmap for ${targetDomain} given skills: ${currentSkills.join(", ")}.`;
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          targetDomain: { type: Type.STRING },
          stages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stageName: { type: Type.STRING },
                description: { type: Type.STRING },
                items: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { topic: { type: Type.STRING }, reason: { type: Type.STRING }, timeEstimate: { type: Type.STRING }, difficulty: { type: Type.STRING } } } }
              }
            }
          }
        }
      }
    }
  });
  return cleanAndParseJSON(response.text || "{}");
};

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut,
  User as FirebaseUser 
} from "firebase/auth";
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  where, 
  orderBy, 
  serverTimestamp,
  getDoc,
  setDoc
} from "firebase/firestore";
import { auth, db } from "../services/firebase";
import { User, Job, Question, Note, UserRole, UserStatus, ChatMessage, Channel, ExtractedResumeData, ResumeSubmission, SystemConfig } from '../types';

interface ResumeContextState {
  rawText: string;
  extractedData: ExtractedResumeData | null;
}

interface AppContextType {
  currentUser: User | null;
  users: User[];
  jobs: Job[];
  questions: Question[];
  notes: Note[];
  messages: ChatMessage[];
  channels: Channel[];
  resumeContext: ResumeContextState;
  systemConfig: SystemConfig;

  login: (email: string, password?: string) => Promise<void>;
  logout: () => void;
  register: (name: string, email: string, role: UserRole, year?: string, password?: string) => Promise<void>;

  addQuestion: (question: any) => Promise<void>;
  updateQuestionStatus: (id: string, status: string) => Promise<void>;
  updateResumeContext: (text: string, data: any) => void;
  addJob: (job: any) => Promise<void>;
  deleteJob: (id: string) => Promise<void>;
  sendMessage: (text: string, channelId: string) => Promise<void>;
  updateUserStatus: (id: string, status: string) => Promise<void>;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [jobs, setJobs] = useState<Job[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [notes, setNotes] = useState<Note[]>([]);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [resumeContext, setResumeContext] = useState<ResumeContextState>({ rawText: '', extractedData: null });
  const [systemConfig] = useState<SystemConfig>({
      announcement: "Welcome to Campus Media v2.0 (Firebase Edition)",
      allowSignups: true,
      maintenanceMode: false,
      interviewCategories: []
  });

  const [channels] = useState<Channel[]>([
      { id: 'general', name: 'General', description: 'General Discussion', type: 'PUBLIC' },
      { id: 'interview-prep', name: 'Interview Prep', description: 'Mock interviews & tips', type: 'PUBLIC' },
      { id: 'jobs', name: 'Jobs', description: 'Job openings & referrals', type: 'PUBLIC' }
  ]);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (fbUser) => {
      if (fbUser) {
        const userDoc = await getDoc(doc(db, "users", fbUser.uid));
        if (userDoc.exists()) {
          setCurrentUser({ ...userDoc.data() as User, id: fbUser.uid });
        }
      } else {
        setCurrentUser(null);
      }
    });
    return () => unsubscribe();
  }, []);

  // Real-time Data Listeners
  useEffect(() => {
    if (!currentUser) return;

    const unsubJobs = onSnapshot(collection(db, "jobs"), (snap) => {
      setJobs(snap.docs.map(d => ({ ...d.data(), id: d.id } as Job)));
    });

    const unsubQuestions = onSnapshot(collection(db, "questions"), (snap) => {
      setQuestions(snap.docs.map(d => ({ ...d.data(), id: d.id } as Question)));
    });

    if (currentUser.role === UserRole.ADMIN) {
      const unsubUsers = onSnapshot(collection(db, "users"), (snap) => {
        setUsers(snap.docs.map(d => ({ ...d.data(), id: d.id } as User)));
      });
      return () => { unsubJobs(); unsubQuestions(); unsubUsers(); };
    }

    return () => { unsubJobs(); unsubQuestions(); };
  }, [currentUser]);

  // Chat listener for active channel
  useEffect(() => {
    const q = query(collection(db, "messages"), orderBy("timestamp", "asc"));
    const unsub = onSnapshot(q, (snap) => {
      setMessages(snap.docs.map(d => ({ ...d.data(), id: d.id } as ChatMessage)));
    });
    return () => unsub();
  }, []);

  const login = async (email: string, password = 'password123') => {
    await signInWithEmailAndPassword(auth, email, password);
  };

  const register = async (name: string, email: string, role: UserRole, year?: string, password = 'password123') => {
    const cred = await createUserWithEmailAndPassword(auth, email, password);
    const userData = {
      name, email, role, year: year || "", status: UserStatus.ACTIVE, joinedDate: new Date().toLocaleDateString()
    };
    await setDoc(doc(db, "users", cred.user.uid), userData);
  };

  const logout = () => signOut(auth);

  const addQuestion = async (qData: any) => {
    await addDoc(collection(db, "questions"), {
      ...qData,
      submittedBy: currentUser?.id,
      submittedByName: currentUser?.name,
      status: currentUser?.role === UserRole.ADMIN ? 'APPROVED' : 'PENDING',
      date: new Date().toLocaleDateString()
    });
  };

  const updateQuestionStatus = async (id: string, status: string) => {
    await updateDoc(doc(db, "questions", id), { status });
  };

  const addJob = async (job: any) => {
    await addDoc(collection(db, "jobs"), { ...job, postedBy: currentUser?.id, postedDate: new Date().toLocaleDateString() });
  };

  const deleteJob = async (id: string) => {
    await deleteDoc(doc(db, "jobs", id));
  };

  const sendMessage = async (text: string, channelId: string) => {
    await addDoc(collection(db, "messages"), {
      text,
      channel: channelId,
      senderId: currentUser?.id,
      senderName: currentUser?.name,
      timestamp: Date.now()
    });
  };

  const updateUserStatus = async (id: string, status: string) => {
    await updateDoc(doc(db, "users", id), { status });
  };

  const updateResumeContext = (text: string, data: any) => {
    setResumeContext({ rawText: text, extractedData: data });
  };

  return (
    <AppContext.Provider value={{
      currentUser, users, jobs, questions, notes, messages, channels, resumeContext, systemConfig,
      login, logout, register, 
      addQuestion, updateQuestionStatus, 
      addJob, deleteJob,
      sendMessage, updateUserStatus, 
      updateResumeContext
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

