pdfjsLib.GlobalWorkerOptions.workerSrc = `https://cdn.jsdelivr.net/npm/pdfjs-dist@${pdfjsLib.version}/build/pdf.worker.min.mjs`;

export const ResumeAnalyzer: React.FC = () => {
  const { currentUser, updateResumeContext } = useApp();
  const [role, setRole] = useState('');
  const [level, setLevel] = useState('Entry-Level');
  const [file, setFile] = useState<File | null>(null);
  const [analysis, setAnalysis] = useState<ResumeAnalysis | null>(null);
  const [loading, setLoading] = useState(false);

  const extractTextFromPDF = async (file: File): Promise<string> => {
    const arrayBuffer = await file.arrayBuffer();
    const pdf = await pdfjsLib.getDocument({ data: arrayBuffer }).promise;
    let fullText = "";
    for (let i = 1; i <= pdf.numPages; i++) {
      const page = await pdf.getPage(i);
      const content = await page.getTextContent();
      const strings = content.items.map((item: any) => item.str);
      fullText += strings.join(" ") + "\n";
    }
    return fullText;
  };

  const handleAnalyze = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!file || !role || !currentUser) return;

    setLoading(true);
    try {
      // 1. Extract Text locally
      const rawText = await extractTextFromPDF(file);

      // 2. AI Analysis
      const result = await analyzeResumeText(rawText, role, level);
      setAnalysis(result);
      updateResumeContext(rawText, result.extractedData);

      // 3. Optional: Store file and analysis in Firebase
      const storageRef = ref(storage, `resumes/${currentUser.id}_${Date.now()}`);
      await uploadBytes(storageRef, file);
      const url = await getDownloadURL(storageRef);

      await addDoc(collection(db, "resumes"), {
        userId: currentUser.id,
        userName: currentUser.name,
        role,
        score: result.score,
        fileUrl: url,
        date: new Date().toLocaleDateString(),
        analysis: result
      });

    } catch (error) {
      console.error("Analysis failed", error);
      alert("Failed to analyze resume. Make sure it's a valid PDF.");
    } finally {
      setLoading(false);
    }
