import { GoogleGenAI, Type } from "@google/genai";
import { InterviewFeedback, Roadmap, ResumeAnalysis } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const cleanAndParseJSON = (text: string) => {
  try {
    const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleaned);
  } catch (e) {
    console.error("JSON Parse Error:", e, "Raw:", text);
    throw new Error("Failed to parse AI response");
  }
};

export const analyzeResumeText = async (text: string, role: string, level: string): Promise<ResumeAnalysis> => {
  const prompt = `
    You are an expert ATS (Applicant Tracking System) and Career Coach. 
    Analyze the following resume for a ${role} position at ${level} level.
    TASK:
    1. Extract key data.
    2. Score the resume (0-100).
    3. Provide impact-driven bullet point rewrites.
    4. Identify missing critical hard skills.
    RESUME TEXT: "${text.slice(0, 30000)}"
  `;

  // Fix: Use gemini-3-pro-preview for complex reasoning task (resume analysis)
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          extractedData: {
            type: Type.OBJECT,
            properties: {
              personalInfo: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, email: { type: Type.STRING }, links: { type: Type.ARRAY, items: { type: Type.STRING } } } },
              keySkills: { type: Type.ARRAY, items: { type: Type.STRING } },
              projects: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { name: { type: Type.STRING }, description: { type: Type.STRING } } } },
              workExperience: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { role: { type: Type.STRING }, company: { type: Type.STRING } } } }
            }
          },
          score: { type: Type.NUMBER },
          atsCompatibility: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
          missingSkills: { type: Type.ARRAY, items: { type: Type.STRING } },
          optimizedPoints: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { original: { type: Type.STRING }, optimized: { type: Type.STRING }, reason: { type: Type.STRING } } } },
          summary: { type: Type.STRING }
        }
      }
    }
  });

  return cleanAndParseJSON(response.text || "{}");
};

export const generateFeedbackFromTranscript = async (transcript: string): Promise<InterviewFeedback> => {
  const prompt = `Evaluate this interview: "${transcript}". Provide score, mistakes, and ideal answers.`;
  // Fix: Use gemini-3-pro-preview for complex reasoning task (interview evaluation)
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          mistakes: { type: Type.ARRAY, items: { type: Type.STRING } },
          improvements: { type: Type.ARRAY, items: { type: Type.STRING } },
          communicationTips: { type: Type.ARRAY, items: { type: Type.STRING } },
          correctedAnswers: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { question: { type: Type.STRING }, originalAnswer: { type: Type.STRING }, idealAnswer: { type: Type.STRING } } } }
        }
      }
    }
  });
  return cleanAndParseJSON(response.text || "{}");
};

export const generateRoadmap = async (currentSkills: string[], targetDomain: string): Promise<Roadmap> => {
  const prompt = `Create a 6-stage roadmap for ${targetDomain} given skills: ${currentSkills.join(", ")}.`;
  // Fix: Use gemini-3-pro-preview for complex reasoning task (roadmap generation)
  const response = await ai.models.generateContent({
    model: "gemini-3-pro-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          targetDomain: { type: Type.STRING },
          stages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stageName: { type: Type.STRING },
                description: { type: Type.STRING },
                items: { type: Type.ARRAY, items: { type: Type.OBJECT, properties: { topic: { type: Type.STRING }, reason: { type: Type.STRING }, timeEstimate: { type: Type.STRING }, difficulty: { type: Type.STRING } } } }
              }
            }
          }
        }
      }
    }
  });
  return cleanAndParseJSON(response.text || "{}");
};

import { GoogleGenAI, Type } from "@google/genai";
import dotenv from 'dotenv';

dotenv.config();

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean JSON string if model adds markdown formatting
const cleanAndParseJSON = (text: string) => {
  try {
    // Remove markdown code blocks if present
    const cleaned = text.replace(/```json/g, '').replace(/```/g, '').trim();
    return JSON.parse(cleaned);
  } catch (e) {
    console.error("JSON Parse Error:", e);
    console.error("Raw Text:", text);
    throw new Error("Failed to parse AI response");
  }
};

export const analyzeResumeText = async (text: string, role: string, level: string) => {
  // Fix: Use gemini-3-pro-preview for complex reasoning task (resume analysis)
  const model = "gemini-3-pro-preview";
  const prompt = `
    You are an expert ATS (Applicant Tracking System) and Career Coach. 
    Analyze the following resume for a ${role} position at ${level} level.

    TASK:
    1. Extract key data.
    2. Score the resume from 0-100 based on relevance to the role and ATS formatting best practices.
    3. Provide concrete examples of how to rewrite bullet points to be impact-driven (Action Verb + Task + Result).
    4. Identify missing hard skills critical for this specific role.

    RESUME TEXT: 
    "${text.slice(0, 30000)}"
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          extractedData: {
            type: Type.OBJECT,
            properties: {
              personalInfo: {
                 type: Type.OBJECT,
                 properties: {
                    name: { type: Type.STRING },
                    email: { type: Type.STRING },
                    links: { type: Type.ARRAY, items: { type: Type.STRING } }
                 }
              },
              keySkills: { type: Type.ARRAY, items: { type: Type.STRING } },
              projects: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    techStack: { type: Type.ARRAY, items: { type: Type.STRING } },
                    description: { type: Type.STRING }
                  }
                }
              },
              workExperience: {
                type: Type.ARRAY,
                items: {
                  type: Type.OBJECT,
                  properties: {
                    role: { type: Type.STRING },
                    company: { type: Type.STRING },
                    duration: { type: Type.STRING },
                  }
                }
              },
            }
          },
          score: { type: Type.NUMBER },
          atsCompatibility: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          weaknesses: { type: Type.ARRAY, items: { type: Type.STRING } },
          suggestions: { type: Type.ARRAY, items: { type: Type.STRING } },
          missingSkills: { type: Type.ARRAY, items: { type: Type.STRING } },
          optimizedPoints: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                original: { type: Type.STRING },
                optimized: { type: Type.STRING },
                reason: { type: Type.STRING }
              }
            }
          },
          summary: { type: Type.STRING }
        }
      },
    },
  });

  if (!response.text) throw new Error("AI Error");
  return cleanAndParseJSON(response.text);
};

export const generateFeedback = async (transcript: string) => {
  // Fix: Use gemini-3-pro-preview for complex reasoning task (interview feedback)
  const model = "gemini-3-pro-preview";
  const prompt = `
    You are a Senior Technical Interviewer. Analyze the following voice interview transcript.
    TRANSCRIPT:
    "${transcript}"

    Provide a strict performance report.
    - Identify exactly where the candidate failed to answer correctly.
    - Provide "Corrected Answers" for mistakes.
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          score: { type: Type.NUMBER },
          strengths: { type: Type.ARRAY, items: { type: Type.STRING } },
          mistakes: { type: Type.ARRAY, items: { type: Type.STRING } },
          improvements: { type: Type.ARRAY, items: { type: Type.STRING } },
          communicationTips: { type: Type.ARRAY, items: { type: Type.STRING } },
          technicalTips: { type: Type.ARRAY, items: { type: Type.STRING } },
          correctedAnswers: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                question: { type: Type.STRING },
                originalAnswer: { type: Type.STRING },
                idealAnswer: { type: Type.STRING },
              },
            },
          },
          roadmap: { type: Type.ARRAY, items: { type: Type.STRING } },
        },
      },
    },
  });

  if (!response.text) throw new Error("No feedback generated");
  return cleanAndParseJSON(response.text);
};

export const generateRoadmap = async (currentSkills: string[], targetDomain: string) => {
  // Fix: Use gemini-3-pro-preview for complex reasoning task (roadmap generation)
  const model = "gemini-3-pro-preview";
  const prompt = `
    Create a detailed, step-by-step 6-Stage Learning Roadmap for a student targeting the domain: "${targetDomain}".
    Current Skills: ${currentSkills.join(", ")}.

    Instructions:
    - If current skills are empty, assume beginner.
    - Stage 1 should be foundations, Stage 6 should be mastery/advanced projects.
    - Provide resource keywords (e.g. "MDN Docs", "Coursera", "Official Docs").
    - Time estimate should be realistic (e.g., "2 weeks").
  `;

  const response = await ai.models.generateContent({
    model,
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          targetDomain: { type: Type.STRING },
          stages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                stageName: { type: Type.STRING },
                description: { type: Type.STRING },
                items: {
                  type: Type.ARRAY,
                  items: {
                    type: Type.OBJECT,
                    properties: {
                      topic: { type: Type.STRING },
                      reason: { type: Type.STRING },
                      timeEstimate: { type: Type.STRING },
                      difficulty: { type: Type.STRING, enum: ["Easy", "Medium", "Hard"] },
                      resources: { type: Type.ARRAY, items: { type: Type.STRING } }
                    }
                  }
                }
              }
            }
          }
        }
      },
    },
  });

  if (!response.text) throw new Error("Roadmap generation failed");
  return cleanAndParseJSON(response.text);
};

import React, { useState, useRef, useEffect } from 'react';
import { Mic, MicOff, Play, PhoneOff, Award, RotateCcw, Volume2, Activity, FileText } from 'lucide-react';
import { GoogleGenAI, LiveServerMessage, Modality } from '@google/genai';
import { generateFeedbackFromTranscript } from '../services/geminiService';
import { InterviewFeedback } from '../types';
import { useApp } from '../context/AppContext';
import { base64ToUint8Array, arrayBufferToBase64, decodeAudioData, float32ToInt16 } from '../utils/audioUtils';

export const MockInterview: React.FC = () => {
  const { resumeContext } = useApp();

  // Config State
  const [role, setRole] = useState('');
  const [type, setType] = useState('Technical');
  const [level, setLevel] = useState('Entry-Level');

  // Session State
  const [isConnected, setIsConnected] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false); // AI Speaking
  const [userSpeaking, setUserSpeaking] = useState(false); // User Speaking visualizer
  const [feedback, setFeedback] = useState<InterviewFeedback | null>(null);
  const [loadingFeedback, setLoadingFeedback] = useState(false);

  // Transcripts
  const transcriptRef = useRef<string>("");

  // Audio Refs
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const inputSourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);

  const sessionRef = useRef<Promise<any> | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourceNodesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const isSessionActiveRef = useRef<boolean>(false);

  useEffect(() => {
    return () => {
      stopSession();
    };
  }, []);

  const startSession = async () => {
    if (!role) return;

    // Ensure previous session is fully cleaned up
    await stopSession();

    transcriptRef.current = "";
    setFeedback(null);
    isSessionActiveRef.current = true;

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const audioCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
      inputAudioContextRef.current = audioCtx;

      const source = audioCtx.createMediaStreamSource(stream);
      const processor = audioCtx.createScriptProcessor(4096, 1, 1);

      inputSourceRef.current = source;
      processorRef.current = processor;

      source.connect(processor);
      processor.connect(audioCtx.destination);

      const outCtx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      outputAudioContextRef.current = outCtx;

      const resumeSnippet = resumeContext.rawText 
        ? `CANDIDATE RESUME: "${resumeContext.rawText.slice(0, 5000)}"` 
        : "CANDIDATE RESUME: Not provided. Ask general questions.";

      const systemInstruction = `
        You are an expert Voice Interviewer for a "${role}" role (${type}, ${level}).

        ${resumeSnippet}

        PROTOCOL (STRICTLY FOLLOW THIS SEQUENCE):
        1. GREETING: Brief, friendly welcome.
        2. QUESTION 1 (EASY): Based on a specific skill in their resume.
        3. QUESTION 2 (EASY): Based on another skill/intro.
        4. QUESTION 3 (MEDIUM): Scenario based on their projects/experience.
        5. QUESTION 4 (MEDIUM): Technical depth question on their domain.
        6. QUESTION 5 (MEDIUM): Problem-solving scenario.
        7. QUESTION 6 (HARD): Advanced edge-case or system design question.
        8. QUESTION 7 (HARD): Deep dive into a resume project's architecture.
        9. CLOSING: Thank them.

        RULES:
        - ASK ONLY ONE QUESTION AT A TIME.
        - WAIT for the user to answer before proceeding.
        - Keep your speech CONCISE (2-3 sentences max).
        - Speak naturally, acknowledge answers briefly ("Good point", "I see") before the next question.
        - DO NOT list the questions. Perform the interview live.
      `;

      // Fix: Create GoogleGenAI instance right before starting the session as per guidelines
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      // Fix: Updated model to the latest gemini-2.5-flash-native-audio-preview-12-2025
      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction: systemInstruction,
          inputAudioTranscription: {}, 
          outputAudioTranscription: {},
        },
        callbacks: {
          onopen: () => {
            console.log("Session Opened");
            setIsConnected(true);
          },
          onmessage: async (message: LiveServerMessage) => {
            if (!isSessionActiveRef.current) return;

            if (message.serverContent?.outputTranscription?.text) {
               transcriptRef.current += `AI: ${message.serverContent.outputTranscription.text}\n`;
            }
            if (message.serverContent?.inputTranscription?.text) {
               transcriptRef.current += `User: ${message.serverContent.inputTranscription.text}\n`;
            }

            const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio) {
              setIsSpeaking(true);
              try {
                // Ensure output context is valid
                if (!outputAudioContextRef.current || outputAudioContextRef.current.state === 'closed') return;

                const audioData = base64ToUint8Array(base64Audio);
                const audioBuffer = await decodeAudioData(audioData, outputAudioContextRef.current, 24000, 1);

                // Double check active state after async decode
                if (!isSessionActiveRef.current || !outputAudioContextRef.current) return;

                const source = outputAudioContextRef.current.createBufferSource();
                source.buffer = audioBuffer;
                source.connect(outputAudioContextRef.current.destination);

                const currentTime = outputAudioContextRef.current.currentTime;
                const startTime = Math.max(currentTime, nextStartTimeRef.current);
                source.start(startTime);
                nextStartTimeRef.current = startTime + audioBuffer.duration;

                sourceNodesRef.current.add(source);
                source.onended = () => {
                  sourceNodesRef.current.delete(source);
                  if (sourceNodesRef.current.size === 0) setIsSpeaking(false);
                };
              } catch (err) {
                console.error("Audio decoding/playback error:", err);
              }
            }

            if (message.serverContent?.interrupted) {
              sourceNodesRef.current.forEach(node => {
                try { node.stop(); } catch(e) {}
              });
              sourceNodesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsSpeaking(false);
            }
          },
          onclose: (e) => {
            console.log("Session Closed", e);
            if (isSessionActiveRef.current) {
                stopSession();
            }
          },
          onerror: (e) => {
            console.error("Session Error", e);
            if (isSessionActiveRef.current) {
                stopSession();
            }
          }
        }
      });

      sessionRef.current = sessionPromise;

      processor.onaudioprocess = (e) => {
        if (!isSessionActiveRef.current) return;

        const inputData = e.inputBuffer.getChannelData(0);
        const sum = inputData.reduce((a, b) => a + Math.abs(b), 0);
        setUserSpeaking(sum > 10);

        const pcm16 = float32ToInt16(inputData);
        const uint8 = new Uint8Array(pcm16.buffer);
        const base64 = arrayBufferToBase64(uint8.buffer);

        const currentSessionPromise = sessionRef.current;
        if (currentSessionPromise) {
            currentSessionPromise.then(async (session) => {
                if (isSessionActiveRef.current) {
                    try {
                      await session.sendRealtimeInput({
                        media: {
                          mimeType: 'audio/pcm;rate=16000',
                          data: base64
                        }
                      });
                    } catch (error) {
                      // Suppress network errors from sending to closed session
                      console.debug("Send input failed (session likely closed):", error);
                    }
                }
            }).catch(() => {
                // Ignore promise rejection if session connect failed
            });
        }
      };

    } catch (error) {
      console.error("Failed to start session", error);
      alert("Could not access microphone or start session.");
      stopSession();
    }
  };

  const stopSession = async () => {
    isSessionActiveRef.current = false;
    setIsConnected(false);
    setIsSpeaking(false);
    setUserSpeaking(false);

    // 1. Close Session
    if (sessionRef.current) {
      const currentSessionPromise = sessionRef.current;
      sessionRef.current = null; // Prevent re-entry
      try {
        const session = await currentSessionPromise;
        await session.close();
      } catch (e) {
        console.debug("Session close error ignored", e);
      }
    }

    // 2. Stop Media Stream (Release Microphone)
    if (streamRef.current) {
        try {
            streamRef.current.getTracks().forEach(track => track.stop());
        } catch(e) {}
        streamRef.current = null;
    }

    // 3. Disconnect Nodes
    if (inputSourceRef.current) {
      try { inputSourceRef.current.disconnect(); } catch (e) {}
      inputSourceRef.current = null;
    }
    if (processorRef.current) {
      try { processorRef.current.disconnect(); } catch (e) {}
      processorRef.current = null;
    }

    // 4. Stop All Audio Sources
    sourceNodesRef.current.forEach(n => {
        try { n.stop(); } catch (e) {}
    });
    sourceNodesRef.current.clear();
    nextStartTimeRef.current = 0;

    // 5. Close Audio Contexts Safely
    const closeContext = async (ref: React.MutableRefObject<AudioContext | null>) => {
        if (ref.current) {
            const ctx = ref.current;
            ref.current = null; // Prevent re-entry
            try {
                if (ctx.state !== 'closed') {
                    await ctx.close();
                }
            } catch (e) {
                // Ignore "Cannot close a closed AudioContext" errors
                console.debug("AudioContext close ignored", e);
            }
        }
    };

    await Promise.all([
        closeContext(inputAudioContextRef),
        closeContext(outputAudioContextRef)
    ]);
  };

  const handleEndSession = async () => {
     await stopSession();
     if (!transcriptRef.current) return;
     setLoadingFeedback(true);
     try {
       const result = await generateFeedbackFromTranscript(transcriptRef.current);
       setFeedback(result);
     } catch (e) {
       console.error("Feedback generation failed", e);
       alert("Could not generate feedback report.");
     } finally {
       setLoadingFeedback(false);
     }
  };

  const reset = () => {
    setFeedback(null);
    transcriptRef.current = "";
  };

  if (feedback) {
    return (
      <div className="max-w-4xl mx-auto space-y-8 animate-in fade-in duration-500 pb-10">
        <div className="flex justify-between items-center">
          <h1 className="text-2xl font-bold text-slate-800">Performance Report</h1>
          <button onClick={reset} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg hover:bg-indigo-700">
            <RotateCcw size={18} /> New Interview
          </button>
        </div>

        <div className="bg-white p-6 rounded-xl shadow-md border-t-4 border-indigo-600 flex items-center justify-between">
          <div>
            <p className="text-slate-500 font-medium">Interview Score</p>
            <p className="text-5xl font-bold text-slate-800">{feedback.score}<span className="text-2xl text-slate-400">/10</span></p>
          </div>
          <Award size={64} className="text-yellow-500" />
        </div>

        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-100">
          <h3 className="font-bold text-slate-800 mb-4 text-lg">Corrected Answers (Learning Moments)</h3>
          <div className="space-y-4">
             {feedback.correctedAnswers?.map((item, i) => (
               <div key={i} className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                  <p className="font-bold text-indigo-900 text-sm mb-2">Q: {item.question}</p>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4 text-sm">
                     <div className="text-red-700 bg-red-50 p-2 rounded">
                        <span className="font-bold block text-xs uppercase mb-1">You Said:</span>
                        {item.originalAnswer || "No clear answer"}
                     </div>
                     <div className="text-green-700 bg-green-50 p-2 rounded">
                        <span className="font-bold block text-xs uppercase mb-1">Ideal Answer:</span>
                        {item.idealAnswer}
                     </div>
                  </div>
               </div>
             ))}
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           <div className="bg-green-50 p-6 rounded-xl border border-green-100">
             <h3 className="font-bold text-green-800 mb-3 text-lg">Strengths</h3>
             <ul className="space-y-2">
               {feedback.strengths.map((s, i) => (
                 <li key={i} className="flex items-start gap-2 text-green-700">
                   <span className="mt-1.5 w-1.5 h-1.5 bg-green-500 rounded-full flex-shrink-0" /> {s}
                 </li>
               ))}
             </ul>
           </div>
           <div className="bg-blue-50 p-6 rounded-xl border border-blue-100">
             <h3 className="font-bold text-blue-800 mb-3 text-lg">Improvements</h3>
             <ul className="space-y-2">
               {feedback.improvements.map((s, i) => (
                 <li key={i} className="flex items-start gap-2 text-blue-700">
                   <span className="mt-1.5 w-1.5 h-1.5 bg-blue-500 rounded-full flex-shrink-0" /> {s}
                 </li>
               ))}
             </ul>
           </div>
        </div>
      </div>
    );
  }

  if (loadingFeedback) {
    return (
      <div className="h-full flex flex-col items-center justify-center space-y-4">
        <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
        <h2 className="text-xl font-bold text-slate-800">Generating Feedback Report...</h2>
      </div>
    );
  }

  if (isConnected) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-slate-900 rounded-2xl relative overflow-hidden text-white p-8">
        <div className="absolute inset-0 bg-gradient-to-br from-indigo-900 to-slate-900 opacity-50"></div>
        <div className="relative z-10 flex flex-col items-center space-y-8">
          <div className="text-center">
            <h2 className="text-3xl font-bold mb-2">{role} Interview</h2>
            <p className="text-indigo-200">AI is listening...</p>
          </div>
          <div className={`w-48 h-48 rounded-full flex items-center justify-center transition-all duration-300 ${isSpeaking ? 'bg-indigo-500/20 scale-110 shadow-[0_0_50px_rgba(99,102,241,0.5)]' : 'bg-slate-800'}`}>
            <div className={`w-36 h-36 rounded-full flex items-center justify-center bg-indigo-600 transition-all duration-150 ${isSpeaking ? 'scale-105' : 'scale-100'}`}>
               <Mic size={64} className="text-white" />
            </div>
          </div>
          <div className="text-center space-y-2 h-16">
            <p className="text-xl font-medium animate-pulse">
              {isSpeaking ? "Interviewer Speaking..." : userSpeaking ? "You are speaking..." : "Listening..."}
            </p>
          </div>
          <button 
            onClick={handleEndSession}
            className="group flex items-center gap-3 bg-red-500 hover:bg-red-600 text-white px-8 py-4 rounded-full font-bold text-lg transition-all shadow-lg hover:shadow-red-500/30"
          >
            <PhoneOff size={24} className="group-hover:scale-110 transition-transform" /> End
          </button>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-xl mx-auto w-full my-auto bg-white p-8 rounded-2xl shadow-lg border border-indigo-50">
      <div className="text-center mb-8">
        <div className="w-16 h-16 bg-indigo-100 text-indigo-600 rounded-full flex items-center justify-center mx-auto mb-4">
          <Mic size={32} />
        </div>
        <h1 className="text-2xl font-bold text-slate-900">Voice AI Interviewer</h1>
        <p className="text-slate-500 mt-2">Realistic 7-Question Interview Flow based on your resume.</p>
      </div>

      <div className="space-y-4">
        <div>
          <label className="block text-sm font-medium text-slate-700 mb-1">Target Role</label>
          <input
            type="text"
            placeholder="e.g. Product Manager"
            className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
            value={role}
            onChange={(e) => setRole(e.target.value)}
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Type</label>
            <select 
              className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              value={type}
              onChange={(e) => setType(e.target.value)}
            >
              <option>Technical</option>
              <option>HR</option>
              <option>Managerial</option>
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-slate-700 mb-1">Level</label>
            <select 
              className="w-full p-3 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              value={level}
              onChange={(e) => setLevel(e.target.value)}
            >
              <option>Entry-Level</option>
              <option>Mid-Level</option>
              <option>Senior</option>
            </select>
          </div>
        </div>

        <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
           <div className="flex items-center gap-2 mb-2">
             <FileText size={18} className="text-slate-500" />
             <span className="text-sm font-bold text-slate-700">Resume Context</span>
           </div>
           {resumeContext.rawText ? (
             <div className="text-xs text-green-600 font-medium flex items-center gap-1">
               <span className="w-2 h-2 bg-green-500 rounded-full"></span>
               Loaded from Resume Analyzer ({resumeContext.rawText.length} chars)
             </div>
           ) : (
             <div className="text-xs text-amber-600 font-medium flex items-center gap-1">
               <span className="w-2 h-2 bg-amber-500 rounded-full"></span>
               No resume detected. Questions will be generic. (Go to Resume AI first)
             </div>
           )}
        </div>

        <button
          onClick={startSession}
          disabled={!role}
          className="w-full py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold shadow-lg shadow-indigo-200 transition-all flex items-center justify-center gap-2 disabled:opacity-50"
        >
          <Play size={20} fill="currentColor" /> Start Interview
        </button>
      </div>
    </div>
  );
};

import React, { createContext, useContext, useState, ReactNode, useEffect } from 'react';
import { 
  onAuthStateChanged, 
  signInWithEmailAndPassword, 
  createUserWithEmailAndPassword, 
  signOut 
} from "firebase/auth";
import { 
  collection, 
  onSnapshot, 
  addDoc, 
  updateDoc, 
  deleteDoc, 
  doc, 
  query, 
  orderBy, 
  getDoc,
  setDoc
} from "firebase/firestore";
import { auth, db } from "../services/firebase";
import { User, Job, Question, Note, UserRole, UserStatus, ChatMessage, Channel, ExtractedResumeData, SystemConfig } from '../types';

interface ResumeContextState {
  rawText: string;
  extractedData: ExtractedResumeData | null;
}

interface AppContextType {
  currentUser: User | null;
  users: User[];
  jobs: Job[];
  questions: Question[];
  notes: Note[];
  messages: ChatMessage[];
  channels: Channel[];
  resumeContext: ResumeContextState;
  systemConfig: SystemConfig;

  login: (email: string, password: string) => Promise<void>;
  logout: () => Promise<void>;
  register: (name: string, email: string, password: string, role: UserRole, year?: string) => Promise<void>;

  addQuestion: (question: any) => Promise<void>;
  updateQuestionStatus: (id: string, status: string) => Promise<void>;
  updateResumeContext: (text: string, data: any) => void;
  addJob: (job: any) => Promise<void>;
  deleteJob: (id: string) => Promise<void>;
  sendMessage: (text: string, channelId: string) => Promise<void>;
  updateUserStatus: (id: string, status: string) => Promise<void>;
}

const AppContext = createContext<AppContextType | undefined>(undefined);

export const AppProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [users, setUsers] = useState<User[]>([]);
  const [jobs, setJobs] = useState<Job[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [notes, setNotes] = useState<Note[]>([]);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [resumeContext, setResumeContext] = useState<ResumeContextState>({ rawText: '', extractedData: null });
  const [systemConfig] = useState<SystemConfig>({
      announcement: "Welcome to Campus Media v2.0",
      allowSignups: true,
      maintenanceMode: false,
      interviewCategories: []
  });

  const [channels] = useState<Channel[]>([
      { id: 'general', name: 'General', description: 'General Discussion', type: 'PUBLIC' },
      { id: 'interview-prep', name: 'Interview Prep', description: 'Mock interviews & tips', type: 'PUBLIC' },
      { id: 'jobs', name: 'Jobs', description: 'Job openings & referrals', type: 'PUBLIC' }
  ]);

  // Auth Listener
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, async (fbUser) => {
      if (fbUser) {
        const userDoc = await getDoc(doc(db, "users", fbUser.uid));
        if (userDoc.exists()) {
          setCurrentUser({ ...userDoc.data() as User, id: fbUser.uid });
        } else {
          // If auth exists but no doc, sign out to prevent broken state
          await signOut(auth);
          setCurrentUser(null);
        }
      } else {
        setCurrentUser(null);
      }
    });
    return () => unsubscribe();
  }, []);

  // Real-time Data Listeners
  useEffect(() => {
    if (!currentUser) return;

    const unsubJobs = onSnapshot(collection(db, "jobs"), (snap) => {
      setJobs(snap.docs.map(d => ({ ...d.data(), id: d.id } as Job)));
    });

    const unsubQuestions = onSnapshot(collection(db, "questions"), (snap) => {
      setQuestions(snap.docs.map(d => ({ ...d.data(), id: d.id } as Question)));
    });

    if (currentUser.role === UserRole.ADMIN) {
      const unsubUsers = onSnapshot(collection(db, "users"), (snap) => {
        setUsers(snap.docs.map(d => ({ ...d.data(), id: d.id } as User)));
      });
      return () => { unsubJobs(); unsubQuestions(); unsubUsers(); };
    }

    return () => { unsubJobs(); unsubQuestions(); };
  }, [currentUser]);

  // Chat listener
  useEffect(() => {
    const q = query(collection(db, "messages"), orderBy("timestamp", "asc"));
    const unsub = onSnapshot(q, (snap) => {
      setMessages(snap.docs.map(d => ({ ...d.data(), id: d.id } as ChatMessage)));
    });
    return () => unsub();
  }, []);

  const login = async (email: string, password: string) => {
    await signInWithEmailAndPassword(auth, email, password);
  };

  const register = async (name: string, email: string, password: string, role: UserRole, year?: string) => {
    const cred = await createUserWithEmailAndPassword(auth, email, password);
    const userData = {
      name, 
      email, 
      role, 
      year: year || "", 
      status: UserStatus.ACTIVE, 
      joinedDate: new Date().toLocaleDateString()
    };
    await setDoc(doc(db, "users", cred.user.uid), userData);
  };

  const logout = async () => {
    await signOut(auth);
  };

  const addQuestion = async (qData: any) => {
    await addDoc(collection(db, "questions"), {
      ...qData,
      submittedBy: currentUser?.id,
      submittedByName: currentUser?.name,
      status: currentUser?.role === UserRole.ADMIN ? 'APPROVED' : 'PENDING',
      date: new Date().toLocaleDateString()
    });
  };

  const updateQuestionStatus = async (id: string, status: string) => {
    await updateDoc(doc(db, "questions", id), { status });
  };

  const addJob = async (job: any) => {
    await addDoc(collection(db, "jobs"), { 
      ...job, 
      postedBy: currentUser?.id, 
      postedDate: new Date().toLocaleDateString() 
    });
  };

  const deleteJob = async (id: string) => {
    await deleteDoc(doc(db, "jobs", id));
  };

  const sendMessage = async (text: string, channelId: string) => {
    await addDoc(collection(db, "messages"), {
      text,
      channel: channelId,
      senderId: currentUser?.id,
      senderName: currentUser?.name,
      timestamp: Date.now()
    });
  };

  const updateUserStatus = async (id: string, status: string) => {
    await updateDoc(doc(db, "users", id), { status });
  };

  const updateResumeContext = (text: string, data: any) => {
    setResumeContext({ rawText: text, extractedData: data });
  };

  return (
    <AppContext.Provider value={{
      currentUser, users, jobs, questions, notes, messages, channels, resumeContext, systemConfig,
      login, logout, register, 
      addQuestion, updateQuestionStatus, 
      addJob, deleteJob,
      sendMessage, updateUserStatus, 
      updateResumeContext
    }}>
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error("useApp must be used within AppProvider");
  return context;
};

import React, { useState } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AppProvider, useApp } from './context/AppContext';
import { Layout } from './components/Layout';
import { Dashboard } from './pages/Dashboard';
import { ResumeAnalyzer } from './pages/ResumeAnalyzer';
import { MockInterview } from './pages/MockInterview';
import { QuestionBank } from './pages/QuestionBank';
import { JobBoard } from './pages/JobBoard';
import { AdminPanel } from './pages/AdminPanel';
import { MentorshipChat } from './pages/MentorshipChat';
import { RoadmapGenerator } from './pages/RoadmapGenerator';
import { UserRole } from './types';
import { Loader2, AlertCircle } from 'lucide-react';

const LoginScreen: React.FC = () => {
  const { login, register } = useApp();
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [role, setRole] = useState<UserRole>(UserRole.STUDENT);
  const [year, setYear] = useState('1st Year');

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      if (isRegistering) {
        await register(name, email, password, role, role === UserRole.STUDENT ? year : undefined);
      } else {
        await login(email, password);
      }
    } catch (err: any) {
      console.error("Auth Error:", err);
      if (err.code === 'auth/user-not-found' || err.code === 'auth/wrong-password' || err.code === 'auth/invalid-credential') {
        setError("Invalid email or password. Please try again.");
      } else if (err.code === 'auth/email-already-in-use') {
        setError("This email is already registered.");
      } else if (err.code === 'auth/weak-password') {
        setError("Password should be at least 6 characters.");
      } else {
        setError("An unexpected error occurred. Please try again.");
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-600 via-indigo-700 to-purple-800 flex items-center justify-center p-4">
      <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-md border border-white/20">
        <div className="text-center mb-8">
          <div className="w-16 h-16 bg-indigo-600 text-white rounded-2xl flex items-center justify-center mx-auto mb-4 text-2xl font-bold shadow-xl shadow-indigo-200">
            C
          </div>
          <h1 className="text-3xl font-extrabold text-slate-900 tracking-tight">Campus Media</h1>
          <p className="text-slate-500 mt-2 font-medium">Elevate Your Career Journey</p>
        </div>

        {error && (
          <div className="mb-6 p-4 bg-red-50 border border-red-100 rounded-xl flex items-center gap-3 text-red-700 text-sm animate-in fade-in slide-in-from-top-2">
            <AlertCircle size={20} className="flex-shrink-0" />
            <p className="font-medium">{error}</p>
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-4">
          {isRegistering && (
             <div className="space-y-4 animate-in fade-in duration-300">
               <input
                 type="text"
                 placeholder="Full Name"
                 className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
                 value={name}
                 onChange={(e) => setName(e.target.value)}
                 required
               />
               <div className="grid grid-cols-2 gap-3">
                  <select 
                    className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    value={role}
                    onChange={(e) => setRole(e.target.value as UserRole)}
                  >
                    <option value={UserRole.STUDENT}>Student</option>
                    <option value={UserRole.ADMIN}>Admin</option>
                  </select>

                  {role === UserRole.STUDENT && (
                    <select 
                      className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                      value={year}
                      onChange={(e) => setYear(e.target.value)}
                    >
                      <option>1st Year</option>
                      <option>2nd Year</option>
                      <option>3rd Year</option>
                      <option>4th Year</option>
                      <option>Alumni</option>
                    </select>
                  )}
               </div>
             </div>
          )}

          <div className="space-y-4">
            <input
              type="email"
              placeholder="Email Address"
              className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
            <input
              type="password"
              placeholder="Password"
              className="w-full p-3.5 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
            />
          </div>

          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-indigo-600 text-white py-4 rounded-xl font-bold hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-100 disabled:opacity-70 flex items-center justify-center gap-2"
          >
            {loading ? (
              <>
                <Loader2 className="animate-spin" size={20} />
                Processing...
              </>
            ) : isRegistering ? 'Create Account' : 'Sign In'}
          </button>
        </form>

        <div className="mt-8 text-center">
           <button 
             onClick={() => {
               setIsRegistering(!isRegistering);
               setError(null);
             }}
             className="text-sm text-indigo-600 hover:text-indigo-800 font-semibold transition-colors"
           >
             {isRegistering ? 'Already have an account? Sign In' : 'New here? Create your student account'}
           </button>
        </div>

        {!isRegistering && (
          <div className="mt-8 pt-6 border-t border-slate-100 text-center">
             <p className="text-xs text-slate-400 font-medium uppercase tracking-wider mb-3">Quick Demo Access</p>
             <div className="flex flex-col gap-2">
                <button 
                  onClick={() => { setEmail('admin@campus.edu'); setPassword('password123'); }}
                  className="text-xs text-indigo-500 hover:bg-indigo-50 py-2 rounded-lg transition-colors border border-indigo-100"
                >
                  Load Admin: admin@campus.edu / password123
                </button>
                <button 
                  onClick={() => { setEmail('john@student.edu'); setPassword('password123'); }}
                  className="text-xs text-slate-500 hover:bg-slate-50 py-2 rounded-lg transition-colors border border-slate-200"
                >
                  Load Student: john@student.edu / password123
                </button>
             </div>
          </div>
        )}
      </div>
    </div>
  );
};

const AppContent: React.FC = () => {
  const { currentUser } = useApp();

  if (!currentUser) {
    return <LoginScreen />;
  }

  return (
    <Routes>
      <Route path="/" element={<Layout />}>
        <Route index element={<Dashboard />} />
        <Route path="resume" element={<ResumeAnalyzer />} />
        <Route path="interview" element={<MockInterview />} />
        <Route path="roadmap" element={<RoadmapGenerator />} />
        <Route path="chat" element={<MentorshipChat />} />
        <Route path="questions" element={<QuestionBank />} />
        <Route path="jobs" element={<JobBoard />} />
        <Route path="admin" element={<AdminPanel />} />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Route>
    </Routes>
  );
};

const App: React.FC = () => {
  return (
    <AppProvider>
      <HashRouter>
        <AppContent />
      </HashRouter>
    </AppProvider>
  );
};

export default App;
